(* ============================================================ *)
(* PROG_TEST: 서보 단독 테스트 (PC 없이)                        *)
(* 용도: 현장 서보 동작 확인용 임시 프로그램                      *)
(* 주의: 테스트 완료 후 이 프로그램 비활성화 할 것                 *)
(*                                                              *)
(* 조작 방법:                                                    *)
(*   _00_IN00 (서보ON 접점) → 서보 전원 ON                       *)
(*   _00_IN13 (리셋SW)      → 1회 누름: 원점복귀                 *)
(*                            원점 완료 후 다시 누름: 360도 회전  *)
(*   _00_IN11 (EMO)         → 비상정지 (항상 유효)               *)
(* ============================================================ *)

PROGRAM PROG_TEST
VAR
    eStep       : INT := 0;     (* 0=대기, 1=원점중, 2=원점완료대기, 3=이동중, 4=완료 *)
    rtButton    : R_TRIG;       (* 리셋SW 상승엣지 *)
    bButton     : BOOL;
    bServoOn    : BOOL;
    bEmo        : BOOL;
END_VAR

(* ================================================================ *)
(* 입력 읽기                                                        *)
(* ================================================================ *)

bButton  := _00_IN13;       (* 리셋 SW *)
bServoOn := _00_IN00;       (* 서보 ON 접점 *)
bEmo     := NOT _00_IN11;   (* EMO: NC접점이므로 반전 *)

rtButton(CLK := bButton);

(* ================================================================ *)
(* Watchdog 우회: PC 없이 동작하도록 SafetyStop 해제                *)
(* (EMO만 살려둠)                                                   *)
(* ================================================================ *)

g_WD_Timeout := FALSE;
g_PC_Ready   := TRUE;
g_SafetyStop := bEmo;       (* EMO일 때만 SafetyStop *)

(* EMO 시 즉시 정지 *)
IF bEmo THEN
    eStep := 0;
    g_FB_Stop(
        Axis    := _MC_AX[0],
        Execute := TRUE,
        Deceleration := 0
    );
    RETURN;
END_IF;

(* ================================================================ *)
(* 스텝 시퀀스                                                     *)
(* ================================================================ *)

CASE eStep OF

0: (* 대기 — 버튼 누르면 원점복귀 시작 *)
    g_bHomeExec  := FALSE;
    g_bMoveExec  := FALSE;
    g_bStopExec  := FALSE;

    IF rtButton.Q AND bServoOn THEN
        g_bHomeExec := TRUE;
        eStep := 1;
    END_IF;

1: (* 원점복귀 실행 중 *)
    g_FB_Home(
        Axis    := _MC_AX[0],
        Execute := g_bHomeExec
    );

    IF g_FB_Home.Done THEN
        g_bHomeExec := FALSE;
        eStep := 2;
    END_IF;

    IF g_FB_Home.Error THEN
        g_bHomeExec := FALSE;
        eStep := 0;    (* 에러 → 대기로 복귀 *)
    END_IF;

2: (* 원점 완료 — 버튼 누르면 360도 회전 *)
    IF rtButton.Q THEN
        (* 목표: 36000 (= 360.00도, 0.01도 단위) *)
        (* 속도: 10000 (= 100.00도/s) *)
        g_bMoveExec := TRUE;
        eStep := 3;
    END_IF;

3: (* 360도 이동 중 *)
    g_FB_MoveAbs(
        Axis         := _MC_AX[0],
        Execute      := g_bMoveExec,
        Position     := 36000.0,     (* 360도 × 100 *)
        Velocity     := 10000.0,     (* 속도 — 현장에서 조정 *)
        Acceleration := 0,           (* 축 기본값 *)
        Deceleration := 0,           (* 축 기본값 *)
        Direction    := 0
    );

    IF g_FB_MoveAbs.Done THEN
        g_bMoveExec := FALSE;
        eStep := 4;
    END_IF;

    IF g_FB_MoveAbs.Error THEN
        g_bMoveExec := FALSE;
        eStep := 0;
    END_IF;

4: (* 이동 완료 — 버튼 누르면 다시 원점복귀부터 *)
    IF rtButton.Q THEN
        g_bHomeExec := TRUE;
        eStep := 1;
    END_IF;

END_CASE;

END_PROGRAM

