(* PC-Based 제어용 Thin PLC                                    *)
(* ============================================================ *)

VAR_GLOBAL
    (* ---- Safety 플래그 ---- *)
    g_SafetyStop   : BOOL := TRUE;   (* TRUE=전출력 차단. 초기값 TRUE(안전) *)
    g_WD_Timeout   : BOOL := FALSE;  (* Watchdog 타임아웃 *)
    g_EMO_Active   : BOOL := FALSE;  (* 비상정지 활성 *)
    g_PC_Ready     : BOOL := FALSE;  (* PC 프로그램 가동 중 *)

    (* ---- Watchdog ---- *)
    g_WD_PrevCount : WORD := 0;      (* 이전 하트비트 값 *)
    g_WD_TON       : TON;            (* 타임아웃 타이머 *)
    g_WD_Changed   : BOOL := FALSE;  (* 하트비트 변화 감지 *)

    (* ---- 서보 명령 엣지 ---- *)
    g_CMD_Home_RT    : R_TRIG;
    g_CMD_Move_RT    : R_TRIG;
    g_CMD_Stop_RT    : R_TRIG;
    g_CMD_Reset_RT   : R_TRIG;
    g_CMD_SetPos_RT  : R_TRIG;

    (* ---- 서보 FB 인스턴스 ---- *)
    g_FB_Home    : MC_Home;
    g_FB_MoveAbs : MC_MoveAbsolute;
    g_FB_JogCW   : MC_Jog;
    g_FB_JogCCW  : MC_Jog;
    g_FB_Stop    : MC_Stop;
    g_FB_Reset   : MC_Reset;
    g_FB_SetPos  : MC_SetPosition;

    (* ---- 서보 실행 플래그 ---- *)
    g_bHomeExec   : BOOL := FALSE;
    g_bMoveExec   : BOOL := FALSE;
    g_bStopExec   : BOOL := FALSE;
    g_bResetExec  : BOOL := FALSE;
    g_bSetPosExec : BOOL := FALSE;

    (* ---- PLC 스캔 카운터 ---- *)
    g_ScanCount : WORD := 0;
END_VAR

