(* ============================================================ *)
(* PROG_SERVO: 서보 모터 제어                                    *)
(* 역할: PC 명령 비트 → MC_xxx FB 실행 → 상태 비트 갱신          *)
(* 축: _MC_AX[0] (인덱스 테이블 서보 1축)                        *)
(* ============================================================ *)

(* SafetyStop 시 서보 긴급 정지 *)
IF g_SafetyStop THEN
    g_bHomeExec   := FALSE;
    g_bMoveExec   := FALSE;
    g_bStopExec   := TRUE;
    g_bResetExec  := FALSE;
    g_bSetPosExec := FALSE;

    g_FB_Stop(Axis := _MC_AX[0], Execute := g_bStopExec, Deceleration := 0);

    %MW400 := 16#0002;
    %MW401 := 0;
    RETURN;
END_IF;

(* 1. PC 명령 비트 읽기 (MW300) *)
bCmdHome    := %MW300.0;
bCmdMove    := %MW300.1;
bCmdJogCW   := %MW300.2;
bCmdJogCCW  := %MW300.3;
bCmdStop    := %MW300.4;
bCmdReset   := %MW300.5;
bCmdSetPos  := %MW300.6;
bCmdServoOn := %MW300.7;

(* 제어 부가 비트 (MW301) *)
bMoveDir    := %MW301.0;
bMoveRel    := %MW301.1;

(* 2. 파라미터 읽기 (MW310~319, DINT = 2 WORD) *)
dinTargetPos := WORD_TO_DINT(%MW310) + WORD_TO_DINT(%MW311) * 65536;
dinTargetVel := WORD_TO_DINT(%MW312) + WORD_TO_DINT(%MW313) * 65536;
dinJogVel    := WORD_TO_DINT(%MW314) + WORD_TO_DINT(%MW315) * 65536;
dinAccel     := WORD_TO_DINT(%MW316) + WORD_TO_DINT(%MW317) * 65536;
dinDecel     := WORD_TO_DINT(%MW318) + WORD_TO_DINT(%MW319) * 65536;

(* 3. 엣지 트리거 검출 *)
g_CMD_Home_RT(CLK := bCmdHome);
g_CMD_Move_RT(CLK := bCmdMove);
g_CMD_Stop_RT(CLK := bCmdStop);
g_CMD_Reset_RT(CLK := bCmdReset);
g_CMD_SetPos_RT(CLK := bCmdSetPos);

(* 4. 명령 실행 플래그 세팅 *)
IF g_CMD_Home_RT.Q THEN
    g_bHomeExec := TRUE;
END_IF;
IF g_FB_Home.Done OR g_FB_Home.Error THEN
    g_bHomeExec := FALSE;
END_IF;

IF g_CMD_Move_RT.Q THEN
    g_bMoveExec := TRUE;
END_IF;
IF g_FB_MoveAbs.Done OR g_FB_MoveAbs.Error THEN
    g_bMoveExec := FALSE;
END_IF;

IF g_CMD_Stop_RT.Q THEN
    g_bStopExec := TRUE;
END_IF;
IF g_FB_Stop.Done OR g_FB_Stop.Error THEN
    g_bStopExec := FALSE;
END_IF;

IF g_CMD_Reset_RT.Q THEN
    g_bResetExec := TRUE;
END_IF;
IF g_FB_Reset.Done OR g_FB_Reset.Error THEN
    g_bResetExec := FALSE;
END_IF;

IF g_CMD_SetPos_RT.Q THEN
    g_bSetPosExec := TRUE;
END_IF;
IF g_FB_SetPos.Done OR g_FB_SetPos.Error THEN
    g_bSetPosExec := FALSE;
END_IF;

(* 5. MC_xxx FB 호출 *)
g_FB_Home(Axis := _MC_AX[0], Execute := g_bHomeExec);

g_FB_MoveAbs(
    Axis         := _MC_AX[0],
    Execute      := g_bMoveExec,
    Position     := DINT_TO_LREAL(dinTargetPos),
    Velocity     := DINT_TO_LREAL(dinTargetVel),
    Acceleration := DINT_TO_LREAL(dinAccel),
    Deceleration := DINT_TO_LREAL(dinDecel),
    Direction    := 0
);

g_FB_JogCW(
    Axis        := _MC_AX[0],
    JogForward  := bCmdJogCW,
    JogBackward := FALSE,
    Velocity    := DINT_TO_LREAL(dinJogVel),
    Acceleration := DINT_TO_LREAL(dinAccel),
    Deceleration := DINT_TO_LREAL(dinDecel)
);

g_FB_JogCCW(
    Axis        := _MC_AX[0],
    JogForward  := FALSE,
    JogBackward := bCmdJogCCW,
    Velocity    := DINT_TO_LREAL(dinJogVel),
    Acceleration := DINT_TO_LREAL(dinAccel),
    Deceleration := DINT_TO_LREAL(dinDecel)
);

g_FB_Stop(
    Axis         := _MC_AX[0],
    Execute      := g_bStopExec,
    Deceleration := DINT_TO_LREAL(dinDecel)
);

g_FB_Reset(Axis := _MC_AX[0], Execute := g_bResetExec);

g_FB_SetPos(
    Axis     := _MC_AX[0],
    Execute  := g_bSetPosExec,
    Position := DINT_TO_LREAL(dinTargetPos)
);

(* 6. 서보 상태 비트 갱신 → MW400 *)
wStatus := 0;

IF _MC_AX[0].IsMoving THEN
    wStatus := wStatus OR 16#0001;
END_IF;
IF _MC_AX[0].Error THEN
    wStatus := wStatus OR 16#0002;
END_IF;
IF _MC_AX[0].InPosition THEN
    wStatus := wStatus OR 16#0004;
END_IF;
IF _MC_AX[0].InPosition AND (NOT _MC_AX[0].IsMoving) THEN
    wStatus := wStatus OR 16#0008;
END_IF;
IF _MC_AX[0].IsHomed THEN
    wStatus := wStatus OR 16#0010;
END_IF;
IF _MC_AX[0].IsHoming THEN
    wStatus := wStatus OR 16#0020;
END_IF;
IF bCmdServoOn AND _00_IN01 THEN
    wStatus := wStatus OR 16#0040;
END_IF;
IF bCmdServoOn AND _MC_AX[0].IsHomed AND (NOT _MC_AX[0].Error) THEN
    wStatus := wStatus OR 16#0080;
END_IF;

%MW400 := wStatus;

(* 7. 명령 응답 비트 갱신 → MW401 *)
wResponse := 0;

IF g_FB_Home.Done THEN
    wResponse := wResponse OR 16#0001;
END_IF;
IF g_FB_MoveAbs.Done THEN
    wResponse := wResponse OR 16#0002;
END_IF;
IF g_FB_Home.Error THEN
    wResponse := wResponse OR 16#0004;
END_IF;
IF g_FB_MoveAbs.Error THEN
    wResponse := wResponse OR 16#0008;
END_IF;
IF g_FB_Reset.Done THEN
    wResponse := wResponse OR 16#0010;
END_IF;

%MW401 := wResponse;

(* 8. 서보 상태값 갱신 → MW410~415 *)
%MW410 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualPosition) MOD 65536);
%MW411 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualPosition) / 65536);
%MW412 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualVelocity) MOD 65536);
%MW413 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualVelocity) / 65536);
%MW414 := _MC_AX[0].ErrorID;
%MW415 := LREAL_TO_WORD(_MC_AX[0].ActualPosition / 100.0);

