(* PROG_SERVO: 서보 모터 제어                                    *)
(* 역할: PC 명령 비트 → MC_xxx FB 실행 → 상태 비트 갱신          *)
(* 축: _MC_AX[0] (인덱스 테이블 서보 1축)                        *)
(* ============================================================ *)

PROGRAM PROG_SERVO
VAR
    (* 명령 비트 (MW0300에서 읽기) *)
    bCmdHome     : BOOL;
    bCmdMove     : BOOL;
    bCmdJogCW    : BOOL;
    bCmdJogCCW   : BOOL;
    bCmdStop     : BOOL;
    bCmdReset    : BOOL;
    bCmdSetPos   : BOOL;
    bCmdServoOn  : BOOL;

    (* 제어 부가 비트 (MW0301) *)
    bMoveDir     : BOOL;
    bMoveRel     : BOOL;

    (* 파라미터 (MW0310~) *)
    dinTargetPos : DINT;
    dinTargetVel : DINT;
    dinJogVel    : DINT;
    dinAccel     : DINT;
    dinDecel     : DINT;

    (* 상태 임시 *)
    wStatus      : WORD := 0;
    wResponse    : WORD := 0;
END_VAR

(* ================================================================ *)
(* SafetyStop 시 서보 긴급 정지                                     *)
(* ================================================================ *)

IF g_SafetyStop THEN
    (* 모든 명령 해제 *)
    g_bHomeExec   := FALSE;
    g_bMoveExec   := FALSE;
    g_bStopExec   := TRUE;    (* 정지만 실행 *)
    g_bResetExec  := FALSE;
    g_bSetPosExec := FALSE;

    (* MC_Stop 실행 *)
    g_FB_Stop(
        Axis     := _MC_AX[0],
        Execute  := g_bStopExec,
        Deceleration := 0    (* 즉시 정지 *)
    );

    (* 상태 비트: 에러 표시 *)
    %MW0400 := 16#0002;   (* STS_ERROR 만 ON *)
    %MW0401 := 0;
    RETURN;
END_IF;

(* ================================================================ *)
(* 1. PC 명령 비트 읽기 (MW0300)                                    *)
(*    MW0300 × 16 = %MX4800                                        *)
(* ================================================================ *)

bCmdHome    := %MX4800;   (* bit0 *)
bCmdMove    := %MX4801;   (* bit1 *)
bCmdJogCW   := %MX4802;   (* bit2 *)
bCmdJogCCW  := %MX4803;   (* bit3 *)
bCmdStop    := %MX4804;   (* bit4 *)
bCmdReset   := %MX4805;   (* bit5 *)
bCmdSetPos  := %MX4806;   (* bit6 *)
bCmdServoOn := %MX4807;   (* bit7 *)

(* 제어 부가 비트 (MW0301 × 16 = %MX4816) *)
bMoveDir    := %MX4816;   (* bit0 *)
bMoveRel    := %MX4817;   (* bit1 *)

(* ================================================================ *)
(* 2. 파라미터 읽기 (MW0310~0319, DINT = 2 WORD 쌍)                *)
(* ================================================================ *)

(* DINT = 하위WORD + 상위WORD×65536 *)
dinTargetPos := WORD_TO_DINT(%MW0310) + WORD_TO_DINT(%MW0311) * 65536;
dinTargetVel := WORD_TO_DINT(%MW0312) + WORD_TO_DINT(%MW0313) * 65536;
dinJogVel    := WORD_TO_DINT(%MW0314) + WORD_TO_DINT(%MW0315) * 65536;
dinAccel     := WORD_TO_DINT(%MW0316) + WORD_TO_DINT(%MW0317) * 65536;
dinDecel     := WORD_TO_DINT(%MW0318) + WORD_TO_DINT(%MW0319) * 65536;

(* ================================================================ *)
(* 3. 엣지 트리거 검출                                              *)
(* ================================================================ *)

g_CMD_Home_RT(CLK := bCmdHome);
g_CMD_Move_RT(CLK := bCmdMove);
g_CMD_Stop_RT(CLK := bCmdStop);
g_CMD_Reset_RT(CLK := bCmdReset);
g_CMD_SetPos_RT(CLK := bCmdSetPos);

(* ================================================================ *)
(* 4. 명령 실행 플래그 세팅 (상승엣지 시 TRUE)                      *)
(* ================================================================ *)

(* 원점복귀: 상승엣지 → 실행 시작, 완료/에러 시 해제 *)
IF g_CMD_Home_RT.Q THEN
    g_bHomeExec := TRUE;
END_IF;
IF g_FB_Home.Done OR g_FB_Home.Error THEN
    g_bHomeExec := FALSE;
END_IF;

(* 절대위치 이동: 상승엣지 → 실행, 완료/에러 시 해제 *)
IF g_CMD_Move_RT.Q THEN
    g_bMoveExec := TRUE;
END_IF;
IF g_FB_MoveAbs.Done OR g_FB_MoveAbs.Error THEN
    g_bMoveExec := FALSE;
END_IF;

(* 정지: 상승엣지 → 실행, 완료 시 해제 *)
IF g_CMD_Stop_RT.Q THEN
    g_bStopExec := TRUE;
END_IF;
IF g_FB_Stop.Done OR g_FB_Stop.Error THEN
    g_bStopExec := FALSE;
END_IF;

(* 에러 리셋: 상승엣지 → 실행, 완료 시 해제 *)
IF g_CMD_Reset_RT.Q THEN
    g_bResetExec := TRUE;
END_IF;
IF g_FB_Reset.Done OR g_FB_Reset.Error THEN
    g_bResetExec := FALSE;
END_IF;

(* 위치 프리셋: 상승엣지 → 실행, 완료 시 해제 *)
IF g_CMD_SetPos_RT.Q THEN
    g_bSetPosExec := TRUE;
END_IF;
IF g_FB_SetPos.Done OR g_FB_SetPos.Error THEN
    g_bSetPosExec := FALSE;
END_IF;

(* ================================================================ *)
(* 5. MC_xxx FB 호출                                                *)
(* ================================================================ *)

(* 5-1. MC_Home — 원점복귀 *)
g_FB_Home(
    Axis     := _MC_AX[0],
    Execute  := g_bHomeExec
);

(* 5-2. MC_MoveAbsolute — 절대위치 이동 *)
g_FB_MoveAbs(
    Axis         := _MC_AX[0],
    Execute      := g_bMoveExec,
    Position     := DINT_TO_LREAL(dinTargetPos),
    Velocity     := DINT_TO_LREAL(dinTargetVel),
    Acceleration := DINT_TO_LREAL(dinAccel),
    Deceleration := DINT_TO_LREAL(dinDecel),
    Direction    := 0     (* 기본: 양방향 최단경로 *)
);

(* 5-3. MC_Jog CW — 정방향 조그 (비트 누르는 동안 유지) *)
g_FB_JogCW(
    Axis     := _MC_AX[0],
    JogForward := bCmdJogCW,
    JogBackward := FALSE,
    Velocity := DINT_TO_LREAL(dinJogVel),
    Acceleration := DINT_TO_LREAL(dinAccel),
    Deceleration := DINT_TO_LREAL(dinDecel)
);

(* 5-4. MC_Jog CCW — 역방향 조그 *)
g_FB_JogCCW(
    Axis     := _MC_AX[0],
    JogForward := FALSE,
    JogBackward := bCmdJogCCW,
    Velocity := DINT_TO_LREAL(dinJogVel),
    Acceleration := DINT_TO_LREAL(dinAccel),
    Deceleration := DINT_TO_LREAL(dinDecel)
);

(* 5-5. MC_Stop — 정지 *)
g_FB_Stop(
    Axis     := _MC_AX[0],
    Execute  := g_bStopExec,
    Deceleration := DINT_TO_LREAL(dinDecel)
);

(* 5-6. MC_Reset — 에러 클리어 *)
g_FB_Reset(
    Axis     := _MC_AX[0],
    Execute  := g_bResetExec
);

(* 5-7. MC_SetPosition — 위치 프리셋 *)
g_FB_SetPos(
    Axis     := _MC_AX[0],
    Execute  := g_bSetPosExec,
    Position := DINT_TO_LREAL(dinTargetPos)
);

(* ================================================================ *)
(* 6. 서보 상태 비트 갱신 → MW0400                                   *)
(*    MW0400 × 16 = %MX6400                                        *)
(* ================================================================ *)

wStatus := 0;

(* bit0: STS_MOVING *)
IF _MC_AX[0].IsMoving THEN
    wStatus := wStatus OR 16#0001;
END_IF;

(* bit1: STS_ERROR *)
IF _MC_AX[0].Error THEN
    wStatus := wStatus OR 16#0002;
END_IF;

(* bit2: STS_IN_POS *)
IF _MC_AX[0].InPosition THEN
    wStatus := wStatus OR 16#0004;
END_IF;

(* bit3: STS_STANDBY — InPosition이면서 Not Moving *)
IF _MC_AX[0].InPosition AND (NOT _MC_AX[0].IsMoving) THEN
    wStatus := wStatus OR 16#0008;
END_IF;

(* bit4: STS_HOMED *)
IF _MC_AX[0].IsHomed THEN
    wStatus := wStatus OR 16#0010;
END_IF;

(* bit5: STS_HOMING *)
IF _MC_AX[0].IsHoming THEN
    wStatus := wStatus OR 16#0020;
END_IF;

(* bit6: STS_SERVO_ON — 서보 전원 상태 *)
IF bCmdServoOn AND _00_IN01 THEN   (* 명령ON + 서보레디 *)
    wStatus := wStatus OR 16#0040;
END_IF;

(* bit7: STS_READY — 서보ON + 원점완료 + 에러없음 *)
IF bCmdServoOn AND _MC_AX[0].IsHomed AND (NOT _MC_AX[0].Error) THEN
    wStatus := wStatus OR 16#0080;
END_IF;

%MW0400 := wStatus;

(* ================================================================ *)
(* 7. 명령 응답 비트 갱신 → MW0401                                   *)
(* ================================================================ *)

wResponse := 0;

(* bit0: RSP_HOME_DONE *)
IF g_FB_Home.Done THEN
    wResponse := wResponse OR 16#0001;
END_IF;

(* bit1: RSP_MOVE_DONE *)
IF g_FB_MoveAbs.Done THEN
    wResponse := wResponse OR 16#0002;
END_IF;

(* bit2: RSP_HOME_ERR *)
IF g_FB_Home.Error THEN
    wResponse := wResponse OR 16#0004;
END_IF;

(* bit3: RSP_MOVE_ERR *)
IF g_FB_MoveAbs.Error THEN
    wResponse := wResponse OR 16#0008;
END_IF;

(* bit4: RSP_RESET_DONE *)
IF g_FB_Reset.Done THEN
    wResponse := wResponse OR 16#0010;
END_IF;

%MW0401 := wResponse;

(* ================================================================ *)
(* 8. 서보 상태값 갱신 → MW0410~0415                                 *)
(* ================================================================ *)

(* 현재 위치 (DINT → 2 WORD) *)
%MW0410 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualPosition) MOD 65536);
%MW0411 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualPosition) / 65536);

(* 현재 속도 (DINT → 2 WORD) *)
%MW0412 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualVelocity) MOD 65536);
%MW0413 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualVelocity) / 65536);

(* 에러 코드 *)
%MW0414 := _MC_AX[0].ErrorID;

(* 현재 위치 (도 단위, 소수점 없음 — HMI 간이 표시용) *)
%MW0415 := LREAL_TO_WORD(_MC_AX[0].ActualPosition / 100.0);

END_PROGRAM
